import React, { useState, useEffect } from 'react';
import api from '../services/api';

const AIAnalysis = () => {
  const [events, setEvents] = useState([]);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [analysis, setAnalysis] = useState(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadEvents();
  }, []);

  const loadEvents = async () => {
    try {
      const res = await api.get('/api/sports/events');
      setEvents(res.data);
    } catch (err) {
      console.error('Erro ao carregar eventos');
    }
  };

  const analyzeEvent = async (event) => {
    setSelectedEvent(event);
    setLoading(true);
    setAnalysis(null);
    try {
      const res = await api.post('/api/ai/analyze', { eventId: event.id });
      setTimeout(() => {
        setAnalysis(res.data);
        setLoading(false);
      }, 2500);
    } catch (err) {
      setLoading(false);
    }
  };

  const sportIcons = { Futebol: '⚽', Basquete: '🏀', 'Tênis': '🎾' };

  const getBarColor = (prob) => {
    const p = parseFloat(prob) * 100;
    if (p >= 50) return '#00c853';
    if (p >= 35) return '#FFD700';
    return '#ff1744';
  };

  const styles = {
    container: { maxWidth: '1200px', margin: '0 auto', padding: '20px' },
    title: { fontFamily: "'Orbitron', sans-serif", fontSize: '32px', fontWeight: 700, marginBottom: '8px', textAlign: 'center' },
    subtitle: { textAlign: 'center', color: '#b0b0b0', marginBottom: '32px', fontSize: '15px' },
    aiHeader: {
      background: 'linear-gradient(135deg, rgba(0,100,255,0.1), rgba(255,215,0,0.05))',
      border: '1px solid rgba(255,215,0,0.2)', borderRadius: '16px', padding: '24px',
      marginBottom: '32px', textAlign: 'center',
    },
    aiIcon: { fontSize: '48px', marginBottom: '12px' },
    aiTitle: { fontFamily: "'Orbitron', sans-serif", fontSize: '18px', color: '#FFD700', marginBottom: '8px' },
    aiDesc: { color: '#b0b0b0', fontSize: '14px', maxWidth: '600px', margin: '0 auto' },
    eventsGrid: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: '16px', marginBottom: '32px' },
    eventCard: (isSelected) => ({
      background: isSelected ? 'linear-gradient(135deg, rgba(0,100,255,0.15), #1a1a1a)' : '#1a1a1a',
      border: isSelected ? '2px solid #4169E1' : '1px solid #2a2a2a',
      borderRadius: '16px', padding: '24px', cursor: 'pointer', transition: 'all 0.3s ease',
    }),
    eventSport: { display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '12px' },
    eventTeams: { fontSize: '18px', fontWeight: 700, marginBottom: '12px' },
    analyzeBtn: {
      background: 'linear-gradient(135deg, #4169E1, #1a3a8a)', color: '#fff',
      border: 'none', padding: '10px 20px', borderRadius: '8px', cursor: 'pointer',
      fontWeight: 600, fontSize: '13px', width: '100%',
    },
    analysisBox: {
      background: '#1a1a1a', border: '1px solid #4169E1', borderRadius: '16px',
      padding: '32px', animation: 'slideUp 0.5s ease',
    },
    analysisTitle: { fontFamily: "'Orbitron', sans-serif", fontSize: '22px', fontWeight: 600, color: '#4169E1', marginBottom: '24px' },
    probRow: { marginBottom: '16px' },
    probLabel: { display: 'flex', justifyContent: 'space-between', marginBottom: '6px', fontSize: '14px' },
    probBar: { height: '12px', borderRadius: '6px', background: '#2a2a2a', overflow: 'hidden' },
    probFill: (prob) => ({
      height: '100%', borderRadius: '6px', width: `${parseFloat(prob) * 100}%`,
      background: `linear-gradient(90deg, ${getBarColor(prob)}, ${getBarColor(prob)}88)`,
      transition: 'width 1s ease',
    }),
    tipBox: {
      background: 'linear-gradient(135deg, rgba(255,215,0,0.1), rgba(0,200,83,0.05))',
      border: '1px solid rgba(255,215,0,0.3)', borderRadius: '12px',
      padding: '20px', marginTop: '24px',
    },
    tipTitle: { color: '#FFD700', fontWeight: 700, fontSize: '16px', marginBottom: '8px' },
    tipText: { color: '#b0b0b0', fontSize: '14px', lineHeight: 1.6 },
    spinner: {
      display: 'flex', flexDirection: 'column', alignItems: 'center',
      padding: '40px', gap: '16px',
    },
    spinnerCircle: {
      width: '50px', height: '50px', border: '4px solid #2a2a2a',
      borderTop: '4px solid #4169E1', borderRadius: '50%',
      animation: 'spin 1s linear infinite',
    },
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>🤖 <span className="gold-text">Análise com IA</span></h1>
      <p style={styles.subtitle}>Inteligência artificial para maximizar seus ganhos</p>

      <div style={styles.aiHeader}>
        <div style={styles.aiIcon}>🧠</div>
        <h3 style={styles.aiTitle}>Motor de Análise Inteligente</h3>
        <p style={styles.aiDesc}>
          Nossa IA analisa dados históricos, forma recente, estatísticas e tendências
          para fornecer previsões precisas e dicas de apostas.
        </p>
      </div>

      <div style={styles.eventsGrid}>
        {events.map(event => (
          <div key={event.id} style={styles.eventCard(selectedEvent?.id === event.id)}>
            <div style={styles.eventSport}>
              <span style={{ fontSize: '24px' }}>{sportIcons[event.sport]}</span>
              <span style={{ color: '#4169E1', fontWeight: 600 }}>{event.sport}</span>
            </div>
            <div style={styles.eventTeams}>
              {event.team1 || event.player1} vs {event.team2 || event.player2}
            </div>
            <button style={styles.analyzeBtn} onClick={() => analyzeEvent(event)}>
              🤖 ANALISAR COM IA
            </button>
          </div>
        ))}
      </div>

      {loading && (
        <div style={styles.spinner}>
          <div style={styles.spinnerCircle}></div>
          <p style={{ color: '#4169E1', fontWeight: 600 }}>Analisando dados com IA...</p>
          <p style={{ color: '#b0b0b0', fontSize: '13px' }}>Processando estatísticas e tendências</p>
        </div>
      )}

      {analysis && !loading && selectedEvent && (
        <div style={styles.analysisBox}>
          <h3 style={styles.analysisTitle}>
            📊 Análise: {selectedEvent.team1 || selectedEvent.player1} vs {selectedEvent.team2 || selectedEvent.player2}
          </h3>

          <div style={styles.probRow}>
            <div style={styles.probLabel}>
              <span style={{ color: '#fff' }}>{selectedEvent.team1 || selectedEvent.player1} vence</span>
              <span style={{ color: '#FFD700', fontWeight: 700 }}>{(parseFloat(analysis.probabilities.team1Win) * 100).toFixed(0)}%</span>
            </div>
            <div style={styles.probBar}>
              <div style={styles.probFill(analysis.probabilities.team1Win)}></div>
            </div>
          </div>

          {analysis.probabilities.draw && (
            <div style={styles.probRow}>
              <div style={styles.probLabel}>
                <span style={{ color: '#fff' }}>Empate</span>
                <span style={{ color: '#FFD700', fontWeight: 700 }}>{(parseFloat(analysis.probabilities.draw) * 100).toFixed(0)}%</span>
              </div>
              <div style={styles.probBar}>
                <div style={styles.probFill(analysis.probabilities.draw)}></div>
              </div>
            </div>
          )}

          <div style={styles.probRow}>
            <div style={styles.probLabel}>
              <span style={{ color: '#fff' }}>{selectedEvent.team2 || selectedEvent.player2} vence</span>
              <span style={{ color: '#FFD700', fontWeight: 700 }}>{(parseFloat(analysis.probabilities.team2Win) * 100).toFixed(0)}%</span>
            </div>
            <div style={styles.probBar}>
              <div style={styles.probFill(analysis.probabilities.team2Win)}></div>
            </div>
          </div>

          <div style={styles.tipBox}>
            <p style={styles.tipTitle}>💡 Dica da IA</p>
            <p style={styles.tipText}>{analysis.tip}</p>
          </div>
        </div>
      )}

      <style>{`@keyframes spin { 0% { transform: rotate(0deg); } 100% { transform: rotate(360deg); } }`}</style>
    </div>
  );
};

export default AIAnalysis;
